#!/usr/bin/env python3
"""Ingest 1000 facts about liver failure, cirrhosis, paracentesis, and orthostatic hypotension into Nova's memory."""
import json, sys, time, urllib.request
from pathlib import Path
from datetime import datetime

sys.path.insert(0, str(Path.home() / ".openclaw/scripts"))
import nova_config

MEMORY_URL = "http://192.168.1.6:18790/remember"
count = 0
failed = 0
start_time = time.time()

def log(msg):
    print(f"[liver-disease {datetime.now().strftime('%H:%M:%S')}] {msg}", flush=True)

def slack_post(text):
    nova_config.post_both(text, slack_channel=nova_config.SLACK_NOTIFY)

def remember(text):
    global count, failed
    payload = json.dumps({"text": text, "source": "local_knowledge", "metadata": {"type": "medical_liver_disease", "topics": ["liver_failure", "cirrhosis", "paracentesis", "orthostatic_hypotension"]}}).encode()
    req = urllib.request.Request(MEMORY_URL, data=payload, headers={"Content-Type": "application/json"}, method="POST")
    try:
        with urllib.request.urlopen(req, timeout=10):
            count += 1
            return True
    except Exception as e:
        failed += 1
        if failed <= 5:
            log(f"  Failed: {e}")
        return False

